1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office - quote (premium)", () => {
5	  // Fee-only baseline
6	  it("should charge 5 G (fee only) for an empty item list", () => {
7	    expect(quote([], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(5);
8	  });
9	
10	  // Single main item base premiums + fee
11	  it("should quote a single sword at 105 G (100 base + 5 fee)", () => {
12	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(105);
13	  });
14	  it("should quote a single amulet at 65 G (60 base + 5 fee)", () => {
15	    expect(quote([{ type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(65);
16	  });
17	  it("should quote a single staff at 85 G (80 base + 5 fee)", () => {
18	    expect(quote([{ type: "staff" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(85);
19	  });
20	  it("should quote a single potion at 45 G (40 base + 5 fee)", () => {
21	    expect(quote([{ type: "potion" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(45);
22	  });
23	
24	  // Multiple main items sum their base premiums
25	  it("should sum base premiums for a sword and an amulet to 165 G (160 base + 5 fee)", () => {
26	    expect(quote([{ type: "sword" }, { type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(165);
27	  });
28	
29	  // Component base premiums
30	  it("should quote a single rune at 30 G (25 base + 5 fee)", () => {
31	    expect(quote([{ type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(30);
32	  });
33	  it("should quote 2 runes at 55 G (50 base + 5 fee)", () => {
34	    expect(quote([{ type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(55);
35	  });
36	
37	  // Building block of 3 alike components
38	  it("should quote 3 runes as a block at 65 G (60 base + 5 fee)", () => {
39	    expect(quote([{ type: "rune" }, { type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(65);
40	  });
41	  it("should quote 4 runes at 105 G (no block, 100 base + 5 fee)", () => {
42	    expect(
43	      quote([{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }], { yearsWithMHPCO: 0, isFollowUp: false })
44	    ).toBe(105);
45	  });
46	  it("should quote 7 runes at 180 G (175 base + 5 fee)", () => {
47	    expect(
48	      quote(
49	        [
50	          { type: "rune" },
51	          { type: "rune" },
52	          { type: "rune" },
53	          { type: "rune" },
54	          { type: "rune" },
55	          { type: "rune" },
56	          { type: "rune" },
57	        ],
58	        { yearsWithMHPCO: 0, isFollowUp: false }
59	      )
60	    ).toBe(180);
61	  });
62	
63	  // Alike = same type only
64	  it("should not form a block for 2 runes + 1 moonstone (75 base + 5 fee = 80 G)", () => {
65	    expect(
66	      quote([{ type: "rune" }, { type: "rune" }, { type: "moonstone" }], { yearsWithMHPCO: 0, isFollowUp: false })
67	    ).toBe(80);
68	  });
69	  it("should form two separate blocks for 3 runes + 3 moonstones (120 base + 5 fee = 125 G)", () => {
70	    expect(
71	      quote(
72	        [
73	          { type: "rune" },
74	          { type: "rune" },
75	          { type: "rune" },
76	          { type: "moonstone" },
77	          { type: "moonstone" },
78	          { type: "moonstone" },
79	        ],
80	        { yearsWithMHPCO: 0, isFollowUp: false }
81	      )
82	    ).toBe(125);
83	  });
84	
85	  // Item-specific modifiers
86	  it("should add 50% curse surcharge to the cursed item's base premium", () => {
87	    expect(quote([{ type: "sword", cursed: true }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(155);
88	  });
89	  it("should add 30% high-enchantment surcharge for enchantment >= 5", () => {
90	    expect(quote([{ type: "sword", enchantment: 5 }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(135);
91	  });
92	  it("should not add high-enchantment surcharge for enchantment 4", () => {
93	    expect(quote([{ type: "sword", enchantment: 4 }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(105);
94	  });
95	  it("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item", () => {
96	    expect(quote([{ type: "sword", cursed: true, enchantment: 5 }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(185);
97	  });
98	
99	  // Modifier scope on multi-item policies
100	  it("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before fee)", () => {
101	    expect(quote([{ type: "sword", cursed: true }, { type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(215);
102	  });
103	
104	  // Policy-wide modifiers
105	  it("should apply 20% loyalty discount for a customer with exactly 2 years", () => {
106	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 2, isFollowUp: false })).toBe(85);
107	  });
108	  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
109	  it.todo("should apply 15% follow-up discount on quotes after the customer's first quote");
110	
111	  // Rounding up in MHPCO's favor
112	  it.todo("should round the final premium up (197.5 G becomes 198 G)");
113	
114	  // Integration examples
115	  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
116	  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");
117	
118	  // Error case
119	  it.todo("should reject a quote containing an item with an unknown type");
120	});
121	
122	describe("Claim Office - claim (payout)", () => {
123	  // Standard reimbursement minus deductible
124	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
125	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
126	
127	  // High-enchantment clause
128	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
129	
130	  // Dragon-material clause
131	  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");
132	
133	  // Conflict: 50% rule wins over dragon
134	  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");
135	
136	  // Threshold confirmation
137	  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");
138	
139	  // Deductible per damage event
140	  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");
141	
142	  // Cap behaviour
143	  it.todo("should cap total payout at twice the insurance sum");
144	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
145	
146	  // Rounding down in MHPCO's favor
147	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
148	
149	  // Error cases
150	  it.todo("should reject a claim whose damage entry references an item not in the policy");
151	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
152	  it.todo("should reject a claim with a negative damage amount");
153	});
