1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PRICE = 60;
19	
20	const COMPONENT_TYPES = ["rune", "moonstone"];
21	
22	const LOYALTY_YEARS_THRESHOLD = 2;
23	const LOYALTY_DISCOUNT_RATE = 0.2;
24	
25	const CURSE_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	
29	const isComponent = (item: { type: string }): boolean =>
30	  COMPONENT_TYPES.includes(item.type);
31	
32	const basePremiumFor = (item: { type: string }): number => BASE_PREMIUM[item.type];
33	
34	const itemPremium = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
35	  const base = basePremiumFor(item);
36	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
37	  const isHighEnchantment = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
38	  const highEnchantmentSurcharge = isHighEnchantment ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
39	  return base + curseSurcharge + highEnchantmentSurcharge;
40	};
41	
42	const componentGroupPremium = (type: string, count: number): number =>
43	  count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUM[type];
44	
45	const loyaltyDiscountFor = (policyBasePremium: number, context: QuoteContext): number =>
46	  context.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBasePremium * LOYALTY_DISCOUNT_RATE : 0;
47	
48	export function quote(items: { type: string; cursed?: boolean; enchantment?: number }[], context: QuoteContext): number {
49	  const componentBasePremium = COMPONENT_TYPES.reduce((sum, type) => {
50	    const count = items.filter((item) => item.type === type).length;
51	    return sum + componentGroupPremium(type, count);
52	  }, 0);
53	
54	  const mainItemsPremium = items
55	    .filter((item) => !isComponent(item))
56	    .reduce((sum, item) => sum + itemPremium(item), 0);
57	
58	  const policyBasePremium = mainItemsPremium + componentBasePremium;
59	
60	  return policyBasePremium - loyaltyDiscountFor(policyBasePremium, context) + POLICY_FEE;
61	}
62	
63	export function claim(): unknown {
64	  return undefined;
65	}
